type FoodItemModalProps = {
  item?: CartItem
  cartItems: CartItem[]
  onClose: () => void
  onItemSave: (item: CartItem) => void
  onItemRemove: (item: CartItem) => void
}

export const FoodItemModal = ({
  item,
  cartItems,
  onClose,
  onItemSave,
  onItemRemove,
}: FoodItemModalProps) => {
  const [quantity, setQuantity] = useState(0)

  const saveItem = useCallback(() => {
    if (item) {
      if (quantity === 0) {
        onItemRemove(item)
      } else {
        onItemSave({ ...item, quantity })
      }
    }

    onClose()
  }, [quantity, onClose, onItemRemove, item, onItemSave])

  useEffect(() => {
    const cartItem = item && cartItems.find((c) => c.id === item.id)
    setQuantity(cartItem?.quantity || 1)
    return () => setQuantity(0)
  }, [cartItems, item])

  return (
    <Modal isOpen={!!item} onClose={onClose}>
      {item && (
        <div>
          <TopContainer>
            <Heading>{item.name}</Heading>
            <StyledBody>{item.description}</StyledBody>
          </TopContainer>
          <BottomContainer>
            <ButtonsContainer>
              <Button
                aria-label="decrease quantity by one"
                round
                clear
                icon="minus"
                onClick={() => setQuantity(quantity - 1)}
                disabled={quantity <= 1}
              />
              <Body type="span">{quantity}</Body>
              <Button
                aria-label="increase quantity by one"
                round
                clear
                icon="plus"
                onClick={() => setQuantity(quantity + 1)}
                disabled={quantity >= 10}
              />
            </ButtonsContainer>
            <StyledButton aria-label="confirm" onClick={saveItem}>
              add for {toCurrency(item.price * quantity)}
            </StyledButton>
          </BottomContainer>
        </div>
      )}
    </Modal>
  )
}

